file.content:
map $http_upgrade $connection_upgrade {
    default keep-alive;
    'websocket' upgrade;
    ''      close;
}

server
{
    listen 80;
    server_name xcollabspace.yottastudios.com;

    return 301 https://$server_name$request_uri;
}

server {
    listen 443 ssl;
    server_name  xcollabspace.yottastudios.com;
    http2 on;
    ssl_certificate /etc/ssl/yottastudios.com/cert.pem;
    ssl_certificate_key /etc/ssl/yottastudios.com/key.pem;

    client_max_body_size    2000m;
    charset utf-8;
    error_page 404 502 503   /404;
    proxy_set_header X-Real-IP $remote_addr;
    proxy_set_header X-Real-PORT $remote_port;
    proxy_set_header X-Original-URI $request_uri;
    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

    add_header Access-Control-Allow-Origin      $http_origin  always;
    add_header Access-Control-Allow-Credentials true         always;
    add_header Access-Control-Allow-Headers '*' always;
    add_header Access-Control-Allow-Methods 'GET,POST,PUT,DELETE,OPTIONS' always;
    add_header Access-Control-Max-Age 17280000 always;
    if ($request_method = OPTIONS) {
        return 204;
    }

    include /etc/nginx/conf.d/xcollabspace/*.conf;
}

