file.content:
map $http_upgrade $connection_upgrade {
    default keep-alive;
    'websocket' upgrade;
    ''      close;
}

server
{
    listen 80;
    server_name xcollabspace-test.xtool-staging.yottastudios.com;
    client_max_body_size    1000m;
    charset utf-8;
    error_page 404 502 503   /404;
    proxy_set_header X-Real-IP $remote_addr;
    proxy_set_header X-Real-PORT $remote_port;
    proxy_set_header X-Original-URI $request_uri;
    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    add_header X-Powered-By 'APITable';

    add_header Access-Control-Allow-Origin "*" always;
    add_header Access-Control-Allow-Methods "GET, POST, OPTIONS, PUT, DELETE" always;
    add_header Access-Control-Allow-Headers "Content-Type, Authorization" always;
    add_header Access-Control-Allow-Private-Network "true" always;

    if ($request_method = OPTIONS) {
        return 204;
    }

    include /etc/nginx/conf.d/xcollabspace-test-server/*.conf;
}

server {
    listen 443 ssl;
    server_name  xcollabspace-test.xtool-staging.yottastudios.com;
    http2 on;
    ssl_certificate /etc/ssl/yottastudios.com/cert.pem;
    ssl_certificate_key /etc/ssl/yottastudios.com/key.pem;

    add_header Access-Control-Allow-Origin "*" always;
    add_header Access-Control-Allow-Methods "GET, POST, OPTIONS, PUT, DELETE" always;
    add_header Access-Control-Allow-Headers "Content-Type, Authorization" always;

    if ($request_method = OPTIONS) {
        return 204;
    }

    include /etc/nginx/conf.d/xcollabspace-test-server/*.conf;
}

