# user www-data;
worker_processes 8;
pid /var/run/nginx.pid;

worker_rlimit_nofile 20480;

events {
	worker_connections 20480;
	multi_accept on;
	use epoll;
}

#server {
#	client_max_body_size 30m;
#}

http {

	##
	# Basic Settings
	##

	sendfile on;
	tcp_nopush on;
	tcp_nodelay on;
	keepalive_timeout 65;
	types_hash_max_size 2048;
	# server_tokens off;

	server_names_hash_bucket_size 128;
	# server_name_in_redirect off;

	include /etc/nginx/mime.types;
	default_type application/octet-stream;

	# Increase request line/header limits to avoid 414 for long URLs
	client_header_buffer_size 16k;
	large_client_header_buffers 8 64k;

	##
	# Logging Settings
	##

	access_log /var/log/nginx/access.log;
	error_log /var/log/nginx/error.log;

	##
	# Gzip Settings
	##

	gzip on;
	gzip_min_length 1024;
	gzip_http_version 1.1;
	gzip_types text/plain application/javascript text/css application/json;
	gzip_comp_level 5;
	gzip_disable "msie6";

	# gzip_vary on;
	# gzip_proxied any;
	# gzip_comp_level 6;
	# gzip_buffers 16 8k;
	# gzip_http_version 1.1;
	# gzip_types text/plain text/css application/json application/x-javascript text/xml application/xml application/xml+rss text/javascript;

	##
	# nginx-naxsi config
	##
	# Uncomment it if you installed nginx-naxsi
	##
	#include /etc/nginx/naxsi_core.rules;
	##
	# nginx-passenger config
	##
	# Uncomment it if you installed nginx-passenger
	##
	#passenger_root /usr;
	#passenger_ruby /usr/bin/ruby;
	##
	# Virtual Host Configs
	##
	client_max_body_size 10000m;

    proxy_cache_path /var/cache/nginx/cache_one levels=1:2 keys_zone=cache_one:10m inactive=7d max_size=1g;

    proxy_cache_path /var/www/bugcollect_cache levels=1:2 keys_zone=bugcollect_cache:300m inactive=20d max_size=1g;
    proxy_cache_path /var/www/testcase_cache levels=1:2 keys_zone=testcase_cache:300m inactive=20d max_size=1g;

	include /etc/nginx/conf.d/*.conf;
	# include /etc/nginx/sites-enabled/*.conf;

	server {
		listen 80;
		listen 443 ssl;
		server_name _; # 所有未匹配到的通配路径

		ssl_certificate /etc/ssl/yottastudios.com/cert.pem;
		ssl_certificate_key /etc/ssl/yottastudios.com/key.pem;

		access_log /var/www/log/default_access.log;
		error_log /var/www/log/default_error.log;

		return 404;
	}
}

